find /path/to/base/dir -type d -exec chmod +rx {} +

find /path/to/base/dir -type f -exec chmod +r {} +
chmod -R a+r /path/to/base/dir
find /path/to/base/dir -type f -exec chmod +r {} \;
find /path/to/base/dir -type f -exec chmod +r {} \;
find /path/to/base/dir -type f -exec chmod +r {} \;

while IFS='=' read -r key value; do export "$key='$value'"; done < <(grep -E '^[^;].*=' file.ini)
awk -F' *= *' '/^[^;].*=/{gsub(/[\r]/,"",$1); export $1="$2"}' file.ini
while IFS='=' read -r key value; do export "$key"="$value"; done < <(grep -E '^[^;#]*=' yourfile.ini)
declare -A config; while IFS='=' read -r key value; do config["$key"]="$value"; done < <(sed 's/^\s*//;s/\s*$//' config.ini | grep -vE '^\[|^;|^$')
grep -oP '^\s*\K[^=]+(?=\s*=\s*[^#]*)' file.ini | while read -r var; do eval "${var}=$(grep -oP "^$var\s*=\s*\K[^#]*" file.ini)"; done

find /path/to/drupal/websites -name 'once*' -exec grep -H 'VERSION' {} \;
find /path/to/drupal/sites -name "CHANGELOG.txt" -exec grep -H "Drupal [0-9]+" {} \;
find /path/to/drupal/sites -name '*.info.yml' -exec grep -H 'version:' {} \;
find /path/to/drupal/sites -name 'version.txt' -exec grep -h 'Version' {} \; | sort | uniq
find /path/to/drupal/websites -name 'composer.json' -exec grep -H '"drupal/core":' {} \; | awk -F'"' '{print $4}' | sort | uniq

find /path/to/drupal/websites -name "CHANGELOG.txt" -exec grep -E "Drupal\s+[0-9]+\.[0-9]+\.[0-9]+" {} \; | awk '{print $2}'
find /path/to/drupal/websites -name "CHANGELOG.txt" -exec awk '/^Version/ {print FILENAME ": " $NF}' {} \;
grep -H -r -o 'version = "[^"]*"' /path/to/drupal/sites/*/settings.php
find /path/to/drupal/websites -name "CHANGELOG.txt" -exec grep -H "Drupal" {} \;
find /path/to/drupal/sites -name "CHANGELOG.txt" -exec grep -H 'Drupal [0-9]*\.[0-9]*\.[0-9]*' {} \;

grep -r "PHPBB_VERSION" /path/to/phpbb/installations/* | awk -F'\"' '{print $2}'
find /path/to/phpbb -name "version.php" -exec grep -H "define('PHPBB_VERSION'" {} \;
find /path/to/phpbb/installations -name "version.php" -exec grep -H '\$config\[' {} \; | awk -F "'" '{print $2}'
find /path/to/phpbb -name "index.php" -exec grep -H "PHPBB" {} \;
find /path/to/phpbb/ -name 'version.php' -exec grep -H 'phpbb_version' {} \;

find /path/to/phpbb/installations -type d -name 'version.php' -exec grep -H 'define(\'VERSION\', ' {} \;
find /path/to/phpbb/installations -name "version.php" -exec grep -H "\$config['version'][]" {} \;
find /path/to/phpbb/ -name "version.php" -exec grep -H "\$config['version']" {} \;
find /path/to/phpbb/ -name "version.php" -exec grep -H "\$version =" {} \;
find /path/to/phpbb/ -name "version.php" -exec grep -H "\$config\['version'\]" {} \; | awk -F'=' '{print $2}' | tr -d " '"

export $(grep '=' myfile | sed 's/^[ \t]*//;s/[ \t]*=[ \t]*/=/;s/\(.*\)/\U\1/;s/["'\'']//g')

eval "$(grep '=' myfile)"
eval $(grep '=' myfile)
export $(grep '=' myfile | sed 's/^[ \t]*//;s/[ \t]*=[ \t]*/=/;' | xargs)
export $(grep '=' myfile | sed 's/#.*//; s/^\s*//; s/\s*$//; s/\(.*\)=\(.*\)/\1="\2"/' | xargs)

pkill -u myuser -o -f $(ps -u myuser -o pid,etime | awk '/[0-9]-/ && $2 ~ /[0-9]+/ {split($2,a,"-"); days=a[1]; hours=substr($2,length($2)-5,2); minutes=substr($2,length($2)-2,2); if(days > 7 || (days == 7 && (hours > 0 || minutes > 0))) print $1}')
pkill -u myuser -o -f "$(ps -eo etime,pid,user | awk '$3=="myuser" && $1~/^[0-9]-[0-9]+:[0-9]+:[0-9]+/ {split($1,a,"-"); split(a[1],b,""); if(b[1]>=7) print $2}')"
find /proc -user myuser -name 'task' -exec bash -c 'ps -p $(basename $(dirname {})) -o etimes= | awk "{if(\$1 > 604800) system(\"kill -9 \" \$(basename $(dirname {}));}"' \;
ps -u myuser -eo pid,lstart --sort=lstart | awk -v cutoff="$(date -d '7 days ago' +%s)" '$2 ~ /[0-9]+/ && mktime($0) < cutoff {print $1}' | xargs kill
find /proc -user myuser -name task -exec sh -c 'for pid in $(ls /proc | grep -E "^[0-9]+$"); do [ -d /proc/$pid ] && [ "$(ps -p $pid -o etime= | awk "{print $1} | awk -F: "{for(i=1;i<=NF;i++){sum+=($i*(60)^(NF-i))}print sum}")" | awk "{print int($1/86400)}")" -gt 7 ] && kill -9 $pid; done' \;
